var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"정말 엄청 크고 으리으리한 유람선이네......","JPN":"大きくて立派な遊覧船だ……","ENG":"This cruise is so big and luxurious-looking...","TWN":"真是艘好大好壯觀的遊輪……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 초호화 크루즈에 타게 된다고?","JPN":"超豪華クルーズ船に乗れるの？","ENG":"I'll be cruising on a super-luxurious ship?","TWN":"我可以坐超豪華的遊輪？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇습니다, 미나 양. 리플레이서 사건을 해결한 공로로 사장님께서 주신 특별 휴가도 함께 말이죠.","JPN":"そうです。リプレイサー事件を解決した功労として、社長が特別休暇とクルーズ船を用意してくださいました。","ENG":"That's right, Mina. On a special vacation awarded to you by the Boss for solving the Replacer case.","TWN":"是的，米娜小姐。作為解決克隆集團事件的獎勵，老闆還給了妳特別假期。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 동안 힘들었던 만큼 푹 쉬고 오시면 되겠군요.","JPN":"今まで大変だった分、ゆっくり休んできてください。","ENG":"You've worked hard. You deserve this.","TWN":"這段時間妳一定很累吧，就趁這個機會去好好休息一下。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저, 정말이야? 와, 이런 건 전혀 기대도 안 했었는데 회사 사정이 좋아졌나 보네.","JPN":"ほ、本当に？　こんなの全然期待してなかったけど、結構儲かってるんだね。","ENG":"A-are you sure? Wow, I never expected anything like this. Our company must be doing better than I thought.","TWN":"真、真的嗎？我完全沒有期待過這種事，看來公司情況有所好轉了呢。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"축제가 있는 섬으로 가는 배라고 했지? 그럼 수영복이라도 새로 사야 하려나?","JPN":"お祭りが開かれる島に向かうって言ってたし、水着を買っていった方がいいかな？","ENG":"So, a ship to a festival island, huh? Maybe I need to buy a new swimsuit.","TWN":"會到一個島上參加慶典嗎？那我是不是該買件新的泳裝？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"헤헤. 어쨌든 사장님께 고맙다고 전해줘.","JPN":"ヘヘッ、とにかく社長にお礼を言っておいて。","ENG":"Heh heh. Anyway, please thank the Boss for me.","TWN":"嘿嘿，不管怎樣，都替我謝謝老闆。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼요, 잘 다녀오세요.","JPN":"わかりました。それではお気をつけて。","ENG":"Sure thing. Enjoy your vacation.","TWN":"好的，祝妳一路順風。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 지난 번에 사장님께서 채굴 의뢰가 너무 안 들어와서 일용직 갑판 청소 의뢰라도 받아야 할 것 같다고 혼잣말을 하시던데......","JPN":"そういえば、この前社長が採掘の依頼が全然入ってこないから、\\n日雇いで甲板掃除の依頼でも引き受けようかとか何とかって言ってたような……","ENG":"Come to think of it, I happened to overhear the Boss debating with himself whether or not we should start taking deck-cleaning jobs because we weren't getting enough mining jobs.","TWN":"話說回來，上次我聽老闆自言自語，說因為很久沒有接到採礦委託，所以得接一些短期的甲板清掃委託呢……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시끄러워요, 시윤 군.","JPN":"黙りなさい。","ENG":"Hush, Shiyoon.","TWN":"你很吵喔，時雲君。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"회사 보안 정책 위반으로 감봉 3개월을 당하기 싫으면 입다무세요.","JPN":"会社のセキュリティポリシー違反で減給3か月になりたくなかったら、その口を閉じた方がいいですよ。","ENG":"You'll keep your mouth shut, or you'll get a pay cut for the next three months for violating the company's security policy.","TWN":"如果你不想因為違反公司保密政策，被罰款三個月薪資的話就閉嘴。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"......휴가라고 하더니.","JPN":"……休暇って言ってたくせに。","ENG":"A vacation, my butt.","TWN":"……還說什麼休假。"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"내 팔자가 그럼 그렇지.","JPN":"まぁ、やけにうまい話だと思ったよ。","ENG":"I knew this was too good to be true.","TWN":"這就是我的人生。"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAILOR_EXTRA_NULL_NULL","text":{"KOREA":"어이, 신참! 어디서 농땡이를 피우고 있나?! 구석구석 꼼꼼히 청소하도록!","JPN":"おい、新入り！　なにサボってたんだ？　隅々まで綺麗に掃除しろよな！","ENG":"Hey, rookie! Stop dilly-dallying and clean each and every nook and cranny!","TWN":"喂，新人！別偷懶！給我好好打掃！"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"네! 네! 선장님!","JPN":"はいっ、船長！","ENG":"Aye, aye, Captain!","TWN":"是！是！船長！"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"SAILOR_EXTRA_NULL_NULL","text":{"KOREA":"야, 야, 날 선장이라 부르지 말랬지! 선장님께서 들으시면 어쩌려고......","JPN":"おいおい、俺のことを船長って呼ぶな！　船長に聞かれたらどうすんだ……","ENG":"Hey, I told you not to call me that! The real Captain would be upset if he heard that.","TWN":"喂喂，說了別叫我船長！萬一被船長聽見了那可怎麼辦……"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};